import { Component, OnInit } from '@angular/core';
import { AnimalService } from 'src/app/services/animal.service';

@Component({
  selector: 'app-how-to-adopt',
  templateUrl: './how-to-adopt.component.html',
  styleUrls: ['./how-to-adopt.component.css']
})
export class HowToAdoptComponent implements OnInit {

  public imgWay: String = "assets/dog_1.jpeg"


  constructor(private animalService: AnimalService) { }

  ngOnInit() {
    console.log('O componente foi inicializado');
    this.getAnimals();

  }

  getAnimals() {

    this.animalService.getAnimals().subscribe(
      animals => {
        // Faça algo com os dados retornados pelo serviço.
        console.log(animals);
      },
      error => {
        // Trate erros, se necessário.
        console.error(error);
      }
    );
  }


  public mudarImagem(novaImagem: String) {
    this.imgWay = novaImagem
  }


}
